<?php
namespace App\Domain\Payouts\Actions;
use App\Enums\PayoutStatus;use App\Enums\PayoutType;use App\Models\PayoutBatch;use Illuminate\Support\Facades\Auth;use Illuminate\Support\Facades\DB;use Illuminate\Support\Str;
class CreatePayoutBatch{public function __construct(private CreatePayout $payouts){}public function execute(array $data):PayoutBatch{if($existing=PayoutBatch::query()->where('idempotency_key',$data['idempotency_key'])->first())return $existing->load('payouts');return DB::transaction(function()use($data){$batch=PayoutBatch::query()->create(['reference'=>'BAT-'.strtoupper(Str::ulid()),'idempotency_key'=>$data['idempotency_key'],'name'=>$data['name'],'type'=>PayoutType::Bulk,'status'=>PayoutStatus::Draft,'created_by'=>Auth::id()]);$total=0;foreach($data['items'] as $index=>$item){$amount=(int)$item['amount_minor'];$total+=$amount;$this->payouts->execute([...$item,'payout_batch_id'=>$batch->id,'idempotency_key'=>$data['idempotency_key'].':'.($index+1)]);}$batch->update(['item_count'=>count($data['items']),'total_amount_minor'=>$total,'status'=>PayoutStatus::PendingReview]);return $batch->refresh()->load('payouts');});}}
